So after looking at your code, I put together a module that extends yours. Needless to say, it got convoluted because there's no easy way of extending jsonplus. Here it is:

```python
from functools import lru_cache
from types import FunctionType

from djmoney.money import Money
from jsonplus import _encoder_default_args, _json_object_hook
from moneyed import EUR
from simplejson import JSONDecoder as SimpleJSONDecoder
from simplejson import JSONEncoder as SimpleJSONEncoder
from simplejson import dumps as simple_dumps
from simplejson import loads as simple_loads


def dump_money(money: Money) -> list:
    """Dump a `Money` instance into JSON format."""
    if money.currency == EUR:
        return [str(money.amount)]
    return [str(money.amount), money.currency.code]


def load_money(json: list) -> Money:
    """Load a `Money` instance from a JSON format."""
    if len(json) == 1:
        return Money(json[0], EUR)
    return Money(json[0], json[1])


def _my_json_default(orig_func: FunctionType) -> FunctionType:
    """Extend `jsonplus`'s functionality with project specific ones."""
    def overrider(obj):
        try:
            return orig_func(obj=obj)
        except TypeError:
            class_type = type(obj)
            if class_type is Money:
                return dict(__class__='Money', __value__=dump_money(money=obj))
            raise
    return overrider


def _my_json_object_hook(obj: dict):
    """Extend `jsonplus`'s functionality with project specific ones."""
    try:
        return _json_object_hook(dict=obj)
    except TypeError:
        classname = obj.get('__class__')
        if classname == 'Money':
            value = obj.get('__value__')
            return load_money(json=value)
        raise


class JSONEncoder(SimpleJSONEncoder):
    """A JSON encoder for objects used in the project."""

    def __init__(self, **kwargs):
        """
        Constructor for simplejson.JSONEncoder, with defaults overriden
        for jsonplus.
        """
        _encoder_default_args(kw=kwargs)
        kwargs['default'] = _my_json_default(orig_func=kwargs['default'])
        super().__init__(**kwargs)


class JSONDecoder(SimpleJSONDecoder):
    """A JSON encoder for objects used in the project."""

    def __init__(self, **kwargs):
        """
        Constructor for simplejson.JSONDecoder, with defaults overriden
        for jsonplus.
        """
        kwargs.update({'object_hook': _my_json_object_hook})
        super().__init__(**kwargs)


def loads(*args, **kwargs):
    kwargs['cls'] = JSONDecoder
    return simple_loads(*args, **kwargs)


def dumps(*args, **kwargs):
    kwargs['cls'] = JSONEncoder
    return simple_dumps(*args, **kwargs)


@lru_cache(maxsize=50)
def loads_cached(dump: str) -> dict:
    """Return (and cache) a loaded JSON state."""
    return loads(s=dump)
```

