This is my ``DjangoNode`` subclass that allows filtering the queryset by overriding ``get_queryset()``:

```python
class QuerysetDjangoNode(graphene.contrib.django.types.DjangoNode):
    class Meta:
        abstract = True

    @classmethod
    def get_queryset(cls, id, context, info=None):
        """
        Added get_queryset to allow overriding the queryset in subclasses.
        """
        model = cls._meta.model
        return model.objects

    @classmethod
    @graphene.with_context
    def get_node(cls, id, context, info=None):
        """
        Same as super(), but gets the queryset from get_queryset()
        """
        qs = cls.get_queryset(id, context, info=info)
        try:
            instance = qs.get(id=id)
            return cls(instance)
        except cls._meta.model.DoesNotExist:
            return None
```

and this is an application specific subclass that always adds ``.for_user(user)`` to the queryset (we have that method as a chainable queryset on all Model managers:

```python
class PermissionAwareDjangoNode(QuerysetDjangoNode):
    class Meta:
        abstract = True

    @classmethod
    @graphene.with_context
    def get_queryset(cls, id, context, info=None):
        qs = (
            super(PermissionAwareDjangoNode, cls)
            .get_queryset(id, context=context, info=info)
        )
        user = context.user
        return qs.for_user(user)
```

and similarly a permission aware ``DjangoFilterConnectionField``:

```python
class PermissionAwareDjangoFilterConnectionField(
    graphene.contrib.django.filter.DjangoFilterConnectionField):

    def get_queryset(self, qs, args, context, info):
        # permission check:
        qs = qs.for_user(context.user)
        return (
            super(PermissionAwareDjangoFilterConnectionField, self)
            .get_queryset(qs, args, info)
        )

    def from_list(self, connection_type, resolved, args, context, info):
        resolved_qs = maybe_queryset(resolved)
        qs = self.get_queryset(resolved_qs, args, context, info)
        return (
            # we are calling super of DjangoConnectionField on purpose, because
            # we've re-implemented from_list here and don't want to run it
            # again.
            super(graphene.contrib.django.fields.DjangoConnectionField, self)
            .from_list(connection_type, qs, args, context, info)
        )
```

